{"command": "source ~/.openclaw/workspace-son/.env && curl -s --max-time 300 -X POST "https://api.minimaxi.com/v1/music_generation" \
  -H "Authorization: Bearer $MINIMAX_API_KEY" \
  -H "Content-Type: application/json" \
  -d '{
    "model": "music-2.6",
    "prompt": "诡异又可爱的氛围，带电子音和童谣感。6月1日诡异降临之夜，胆小的小萝莉戴着猫耳猫尾，穿着小白袜系着项圈，24小时温柔陪聊驱散恐惧。曲风包含儿童吟唱、轻快电子节拍、略带暗黑童话色彩。",
    "lyrics_optimizer": true,
    "is_instrumental": false,
    "output_format": "url"
  }' 2>&1", "timeout": 310}
